import{_ as i,o as a,c as n,ag as t}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"Lineup Builders","description":"","frontmatter":{},"headers":[],"relativePath":"lineup/index.md","filePath":"lineup/index.md"}'),r={name:"lineup/index.md"};function s(o,e,l,p,d,u){return a(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="lineup-builders" tabindex="-1">Lineup Builders <a class="header-anchor" href="#lineup-builders" aria-label="Permalink to &quot;Lineup Builders&quot;">​</a></h1><p>Diamond Analytics includes two lineup builders — Defensive Lineup and Batting Lineup — each using player performance data to make data-driven suggestions.</p><h2 id="defensive-lineup-builder" tabindex="-1">Defensive Lineup Builder <a class="header-anchor" href="#defensive-lineup-builder" aria-label="Permalink to &quot;Defensive Lineup Builder&quot;">​</a></h2><p>The defensive lineup builder suggests optimal defensive alignments based on each player&#39;s fielding percentage at each position.</p><p><strong>How it works:</strong></p><ol><li>Navigate to <strong>Lineups → Defensive Lineup</strong></li><li>The algorithm fills positions using a priority spine: C → P → SS → 2B → 3B → 1B → CF → LF → RF</li><li>Players are placed at their strongest position based on FLD% data</li><li>Override any position by tapping it and selecting a different player</li><li>Locked manual selections are preserved when the lineup auto-updates</li></ol><p><strong>Reading the suggestion:</strong> Each position shows the suggested player with their FLD% at that position. The overall defensive grade updates as you make changes.</p><p><strong>Availability tracking:</strong> Mark players as unavailable before building the lineup. Reasons include injury, absence, rest, pitch count limit, or other. Unavailable players are excluded from suggestions.</p><h2 id="batting-lineup-builder" tabindex="-1">Batting Lineup Builder <a class="header-anchor" href="#batting-lineup-builder" aria-label="Permalink to &quot;Batting Lineup Builder&quot;">​</a></h2><p>The batting lineup builder suggests batting order based on OBP (leadoff), power, and speed metrics.</p><p><strong>How it works:</strong></p><ol><li>Navigate to <strong>Lineups → Batting Lineup</strong></li><li>The algorithm places the highest OBP player in the leadoff spot</li><li>Remaining spots are filled based on a balance of power and contact metrics</li><li>Drag and drop players to reorder the lineup</li><li>The stat comparison panel shows key metrics for each player</li></ol><p><strong>Sparklines:</strong> Each player card shows a mini trend chart of recent at-bat results — a quick visual of current form.</p><p><strong>Saving lineups:</strong> Save any lineup configuration for future reference. Saved lineups appear in your lineup history.</p><h2 id="combined-game-day-card" tabindex="-1">Combined Game Day Card <a class="header-anchor" href="#combined-game-day-card" aria-label="Permalink to &quot;Combined Game Day Card&quot;">​</a></h2><p>The Game Day view shows both the defensive alignment and batting lineup on one screen that can be shared via the Web Share API or copied for printing.</p>',16)])])}const c=i(r,[["render",s]]);export{g as __pageData,c as default};
